-- Tabla: DIM_BANCOS
-- PK: ID_BANCO (NIT_BANCO + COD_ACH, preservando ceros a la izquierda)

CREATE TABLE sgp.[DIM_BANCOS] (
  [ID_BANCO] varchar(13) NOT NULL,
  [COD_SUPERFINANCIERA] varchar(10) NULL,
  [COD_ACH] varchar(4) NOT NULL,
  [RAZON_SOCIAL] varchar(240) NOT NULL,
  [NOMBRE_BANCO] varchar(240) NOT NULL,
  [NIT_BANCO] varchar(9) NOT NULL,
  [NIT_DV] varchar(1) NOT NULL,
  [TIPO_ENTIDAD] varchar(240) NULL,
  [ESTADO_CM] varchar(240) NOT NULL,
  [FECHA_CREACION] date NOT NULL CONSTRAINT DF_DIM_BANCOS_FECHA_CREACION DEFAULT (CONVERT(date, GETDATE())),
  [FECHA_ACTUALIZACION] date NOT NULL CONSTRAINT DF_DIM_BANCOS_FECHA_ACTUALIZACION DEFAULT (CONVERT(date, GETDATE())),
  CONSTRAINT PK_DIM_BANCOS PRIMARY KEY ([ID_BANCO]),
  CONSTRAINT UQ_DIM_BANCOS_COD_ACH UNIQUE ([COD_ACH]),
  CONSTRAINT CK_DIM_BANCOS_ID_BANCO_FORMAT CHECK ([ID_BANCO] = (RIGHT('000000000' + [NIT_BANCO], 9) + RIGHT('0000' + [COD_ACH], 4)))
);
GO

